grid:





























































        select 'this._voucherCode='@@id';load$GridVoucherAttached$(this);' as message
return




        select 'dispose$GridVoucherAttached$(this);' as message
return







/* <flatten type="Javascript"> */
function load$GridVoucherAttached$(g) {
  g.add_itemValueChanged(onChange$GridVoucherAttached$);
  g.add_commandEvent(on$GridVoucherAttached$ExecuteCommand);
  g.$a = {gia_tri: '[gia_tri]:=[gia_tri_nt]*[$ty_gia]'};
}
function dispose$GridVoucherAttached$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherAttached$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherAttached$);} catch (ex) {}
}
function onChange$GridVoucherAttached$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'gia_tri_nt':
      g.validExpression(o, [g.$a.gia_tri]);
      break;
    default:
      break;
  }
}
function on$GridVoucherAttached$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      break;
    default:
      break;
  }
}
/* </flatten> */








